script:
frappe.ui.form.on('Car Booking', {
    // 1. تفعيل تصفية حقل السيارة ديناميكياً بناءً على التصنيف المختار
    setup: function(frm) {
        frm.set_query('car', function() {
            let filters = {
                'status': 'متوفر' // عرض السيارات المتوفرة فقط
            };
            if (frm.doc.category_car) {
                // الفلترة بالاسم البرمجي الصحيح في مستند Car وهو 'categorize'
                filters['categorize'] = frm.doc.category_car;
            }
            return { filters: filters };
        });
    },

    // 2. التحقق الشامل من التواريخ والأيام لمنع أي إدخال خاطئ في قاعدة البيانات
    validate: function(frm) {
        let today = frappe.datetime.get_today(); // جلب تاريخ اليوم بالتقويم الحالي
        
        // أ. التحقق من أن تاريخ بدء الإيجار ليس في الماضي
        if (frm.doc.start_date) {
            if (frm.doc.start_date < today) {
                frappe.throw(__('تاريخ بدء الإيجار لا يمكن أن يكون في الماضي. يجب أن يكون اليوم ({0}) أو تاريخاً مستقبلياً.', [frappe.datetime.str_to_user(today)]));
            }
        }
        
        // ب. التحقق من أن تاريخ انتهاء الإيجار ليس في الماضي
        if (frm.doc.end_date) {
            if (frm.doc.end_date < today) {
                frappe.throw(__('تاريخ انتهاء الإيجار لا يمكن أن يكون في الماضي. يجب أن يكون اليوم ({0}) أو تاريخاً مستقبلياً.', [frappe.datetime.str_to_user(today)]));
            }
        }

        // ج. التحقق من الفارق لمنع الأيام السالبة والالتزام بالحد الأدنى (3 أيام)
        if (frm.doc.start_date && frm.doc.end_date) {
            let diff = frappe.datetime.get_diff(frm.doc.end_date, frm.doc.start_date) + 1;
            
            if (diff < 1) {
                frappe.throw(__('خطأ في التواريخ: تاريخ انتهاء الإيجار لا يمكن أن يكون قبل تاريخ البدء (عدد الأيام سالب).'));
            }
            
            if (diff < 3) {
                frappe.throw(__('ممنوع تأجير السيارات لأقل من 3 أيام كحد أدنى.<br>عدد الأيام بالتاريخ الحالي هو: <b>{0} أيام فقط</b>.', [diff]));
            }
        }
    }
}); // تم تصحيح القوس هنا ليغلق الدالة بالكامل

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        // جعل حقل المسافة الكلية غير قابل للتعديل
        frm.set_df_property('total_distance', 'read_only', 1);
        
        // التحقق من حالة الظهور عند تحميل الصفحة
        toggle_distance_visibility(frm);
    },
    current_odometer: function(frm) {
        toggle_distance_visibility(frm);
    },
    previous_odometer: function(frm) {
        toggle_distance_visibility(frm);
    }
});

function toggle_distance_visibility(frm) {
    let current = frm.doc.current_odometer;
    let previous = frm.doc.previous_odometer || 0;
    
    // التحقق مما إذا كان حقل العداد الحالي يحتوي على قيمة
    if (current !== undefined && current !== null && current !== '') {
        // حساب المسافة
        if (current >= previous) {
            frm.set_value('total_distance', current - previous);
        } else {
            frm.set_value('total_distance', 0);
        }
        // إظهار الحقل
        frm.toggle_display('total_distance', true);
    } else {
        // إخفاء الحقل وتفريغ قيمته إذا كان العداد الحالي فارغاً
        frm.set_value('total_distance', 0);
        frm.toggle_display('total_distance', false);
    }
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_duration(frm);
    },
    // الاستماع لتاريخ الاستلام الفعلي عند تعديله
    receiving_date: function(frm) {
        calculate_duration(frm);
    },
    // الاستماع لتاريخ التسليم في العقد عند تعديله أو جلبه
    pickup_date: function(frm) {
        calculate_duration(frm);
    },
    // الاستماع لحقل الحجز؛ لأن اختيار العقد يقوم بجلب تاريخ التسليم تلقائياً
    booking: function(frm) {
        setTimeout(() => {
            calculate_duration(frm);
        }, 500); // مهلة زمنية قصيرة لضمان جلب البيانات بالكامل
    }
});

function calculate_duration(frm) {
    if (frm.doc.pickup_date && frm.doc.receiving_date) {
        // حساب الفارق الفعلي بالأيام بين تاريخ الاستلام وتاريخ التسليم في العقد
        let diff = frappe.datetime.get_diff(frm.doc.receiving_date, frm.doc.pickup_date);
        
        // إسناد القيمة مباشرة لحقل (عدد الأيام الفعلي)
        frm.set_value('real_days', diff);
    } else {
        frm.set_value('real_days', 0);
    }
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_allowed_limit(frm);
    },
    receiving_date: function(frm) {
        calculate_allowed_limit(frm);
    },
    pickup_date: function(frm) {
        calculate_allowed_limit(frm);
    },
    booking: function(frm) {
        setTimeout(() => {
            calculate_allowed_limit(frm);
        }, 600);
    }
});

function calculate_allowed_limit(frm) {
    let real_days = 0;

    if (frm.doc.pickup_date && frm.doc.receiving_date) {
        real_days = frappe.datetime.get_diff(frm.doc.receiving_date, frm.doc.pickup_date) + 1; // مطابق لـ duration_days في العقد (+1 شامل الطرفين)
        frm.set_value('real_days', real_days);
    } else {
        frm.set_value('real_days', 0);
    }

    let allowed_limit = 0;
    if (real_days > 0) {
        if (real_days < 30) {
            allowed_limit = real_days * 200;
        } else {
            allowed_limit = 4000;
        }
    }

    frm.set_value('allowed_limit', allowed_limit);
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_allowed_limit(frm);
    },
    real_days: function(frm) {
        calculate_allowed_limit(frm);
    }
});

function calculate_allowed_limit(frm) {
    let real_days = cint(frm.doc.real_days) || 0;
    let allowed_limit = 0;

    if (real_days > 0) {
        if (real_days < 30) {
            allowed_limit = real_days * 200;
        } else {
            allowed_limit = 4000;
        }
    }

    frm.set_value('allowed_limit', allowed_limit);
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_extra_distance(frm);
    },
    // الاستماع لحقل إجمالي المسافة المقطوعة عند تغير قيمته
    total_distance: function(frm) {
        calculate_extra_distance(frm);
    },
    // الاستماع لحقل الحد المسموح عند تغير قيمته
    allowed_limit: function(frm) {
        calculate_extra_distance(frm);
    }
});

function calculate_extra_distance(frm) {
    let total_distance = cint(frm.doc.total_distance) || 0;
    let allowed_limit = cint(frm.doc.allowed_limit) || 0;
    let extra_distance = 0;

    // تطبيق شرط الطرح: إذا تجاوزت المسافة المقطوعة الحد المسموح به
    if (total_distance > allowed_limit) {
        extra_distance = total_distance - allowed_limit;
    }

    // وضع النتيجة النهائية في حقل المسافة الإضافية
    frm.set_value('extra_distance', extra_distance);
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_rental_financials(frm);
    },
    // حساب الكلفة بمجرد تحديث حقل الأيام الفعلية من السكربت الآخر
    real_days: function(frm) {
        calculate_rental_financials(frm);
    },
    // حساب الكلفة عند تغيير عقد الحجز المختار
    booking: function(frm) {
        calculate_rental_financials(frm);
    }
});

function calculate_rental_financials(frm) {
    if (!frm.doc.booking) {
        frm.set_value('mainly_cost', 0);
        return;
    }

    // جلب مستند الحجز بالكامل برمجياً لقراءة الأسعار الشرائحية الثلاثة بشكل مضمون
    frappe.db.get_doc('Car Booking', frm.doc.booking)
        .then(doc => {
            if (doc) {
                // قراءة قيم الفئات السعرية الثلاثة المجلوبة من عقد الحجز
                let rate_low = flt(doc.rate_per_day) || 0;        // التكلفة الأصغر (3-7 أيام)
                let rate_mid = flt(doc.تكلفة_الاجار_الشهري) || 0;   // التكلفة الوسطى (7-20 يوماً)
                let rate_high = flt(doc.التكلفة_الاعلى) || 0;      // التكلفة الأعلى (أكثر من 20 يوماً)

                let real_days = cint(frm.doc.real_days) || 0;
                let total_cost = 0;

                if (real_days > 0) {
                    if (real_days <= 7) {
                        // الشريحة الأولى: 7 أيام أو أقل (التكلفة الأصغر)
                        total_cost = real_days * rate_low;
                    } 
                    else if (real_days > 7 && real_days <= 20) {
                        // الشريحة الثانية: من 8 إلى 20 يوماً (التكلفة الوسطى)
                        total_cost = real_days * rate_mid;
                    } 
                    else if (real_days > 20) {
                        // الشريحة الثالثة: أكثر من 20 يوماً (التكلفة الأعلى)
                        total_cost = real_days * rate_high;
                    }
                }

                // تقريب الناتج النهائي لمنزلتين عشريتين
                total_cost = parseFloat(total_cost.toFixed(2));

                // إسناد القيمة الناتجة إلى حقل التكلفة الاساسية
                if (frm.fields_dict['mainly_cost']) {
                    frm.set_value('mainly_cost', total_cost);
                }
            }
        });
}

frappe.ui.form.on("Car Receipt", {
    refresh: function(frm) { calculate_invoice_totals(frm); },
    mainly_cost: function(frm) { calculate_invoice_totals(frm); },
    extra_cost: function(frm) { calculate_invoice_totals(frm); },
    damage: function(frm) { calculate_invoice_totals(frm); },
    booking: function(frm) { setTimeout(() => calculate_invoice_totals(frm), 400); }
});

// الإجمالي قبل الضريبة = الإيجار (أساسي + مسافة زائدة) + الأضرار
// ضريبة الإنفاق = الإيجار × النسبة   |   ضريبة المحلية = ضريبة الإنفاق × النسبة
// الإجمالي النهائي = الإجمالي قبل الضريبة + ضريبة الإنفاق + ضريبة المحلية
function calculate_invoice_totals(frm) {
    let mainly = flt(frm.doc.mainly_cost) || 0;
    let extra  = flt(frm.doc.extra_cost)  || 0;
    let damage = flt(frm.doc.damage)      || 0;

    let rental     = mainly + extra;                              // الأساس الخاضع للضريبة
    let total_cost = parseFloat((rental + damage).toFixed(2));    // الإجمالي قبل الضريبة

    frappe.db.get_single_value("Gate Cars Settings", "spending_tax_rate").then(sr => {
        frappe.db.get_single_value("Gate Cars Settings", "local_tax_rate").then(lr => {
            let spend = parseFloat((rental * (flt(sr) || 0) / 100).toFixed(2));
            let local = parseFloat((spend  * (flt(lr) || 0) / 100).toFixed(2));
            let grand = parseFloat((total_cost + spend + local).toFixed(2));

            frm.set_value("total_cost", total_cost);
            frm.set_value("spending_tax", spend);
            frm.set_value("local_tax", local);
            frm.set_value("grand_total", grand);
        });
    });
}

frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_extra_cost(frm);
    },
    // الاستماع المباشر لحقل المسافة الإضافية فور تحديثه من السكربت الآخر
    extra_distance: function(frm) {
        calculate_extra_cost(frm);
    }
});

function calculate_extra_cost(frm) {
    // قراءة القيمة المخزنة مباشرة في حقل المسافة الإضافية
    let extra_distance = flt(frm.doc.extra_distance) || 0;
    
    // حساب الكلفة الإضافية المترتبة (المسافة الزائدة مضروبة في 0.20)
    let extra_cost = extra_distance * 0.20;
    
    // تقريب الناتج لمنزلتين عشريتين لضمان دقة العمليات المالية
    extra_cost = parseFloat(extra_cost.toFixed(2));
    
    // إسناد القيمة الناتجة مباشرة لحقل الكلفة الإضافية المترتبة
    frm.set_value('extra_cost', extra_cost);
}

frappe.ui.form.on('اسم الدوك تايب الجديد', {
    onload: function(frm) {
        update_car_count(frm);
    },
    refresh: function(frm) {
        update_car_count(frm);
    }
});

function update_car_count(frm) {
    frappe.db.count('Car')
        .then(count => {
            frm.set_value('total_car', count);
        });
}

frappe.ui.form.on('Car Booking', {
    // 1. تفعيل تصفية حقل السيارة ديناميكياً بناءً على التصنيف المختار
    setup: function(frm) {
        frm.set_query('car', function() {
            let filters = {
                'status': 'متوفر' // عرض السيارات المتوفرة فقط
            };
            if (frm.doc.category_car) {
                // الفلترة بالاسم البرمجي الصحيح في مستند Car وهو 'categorize'
                filters['categorize'] = frm.doc.category_car;
            }
            return { filters: filters };
        });
    },
    
    refresh: function(frm) {
        calculate_rental_financials(frm);
    },

    start_date: function(frm) {
        calculate_rental_financials(frm);
    },

    end_date: function(frm) {
        calculate_rental_financials(frm);
    },

    // جلب تصنيف السيارة تلقائياً بمجرد اختيار السيارة
    car: function(frm) {
        if (frm.doc.car) {
            // جلب قيمة حقل categorize من مستند السيارة المختار
            frappe.db.get_value('Car', frm.doc.car, 'categorize')
                .then(r => {
                    let values = r.message || r;
                    if (values && values.categorize) {
                        frm.set_value('category_car', values.categorize);
                    }
                    calculate_rental_financials(frm);
                });
        } else {
            calculate_rental_financials(frm);
        }
    },

    // مسح اختيار السيارة إذا قام الموظف بتغيير التصنيف لسيارة لا تطابق التصنيف الجديد
    category_car: function(frm) {
        if (frm.doc.car && frm.doc.category_car) {
            frappe.db.get_value('Car', frm.doc.car, 'categorize')
                .then(r => {
                    let values = r.message || r;
                    if (values && values.categorize !== frm.doc.category_car) {
                        frm.set_value('car', '');
                        frappe.show_alert({
                            message: __('تم تفريغ حقل السيارة لأنها لا تنتمي للتصنيف المختار الجديد'),
                            indicator: 'orange'
                        });
                    }
                });
        }
    }
});

frappe.ui.form.on('Car Booking', {
    // 1. عند حفظ الحجز كمسودة (Draft) -> تتحول السيارة إلى "محجوز"
    after_save: function(frm) {
        if (frm.doc.car && frm.doc.docstatus === 0) {
            frappe.db.set_value('Car', frm.doc.car, 'status', 'محجوز')
                .then(() => {
                    frappe.show_alert({
                        message: __('تم حفظ الحجز كمسودة، وحالة السيارة {0} الآن: [محجوز]', [frm.doc.car]),
                        indicator: 'orange'
                    });
                });
        }
    },

    // 2. عند تقديم واعتماد الحجز (Submit) -> تتحول السيارة إلى "مؤجر"
    on_submit: function(frm) {
        if (frm.doc.car) {
            frappe.db.set_value('Car', frm.doc.car, 'status', 'مؤجر')
                .then(() => {
                    frappe.show_alert({
                        message: __('تم اعتماد عقد الحجز بنجاح، وحالة السيارة {0} الآن: [مؤجر]', [frm.doc.car]),
                        indicator: 'green'
                    });
                });
        }
    },

    // 3. عند إلغاء عقد الحجز المعتمد (Cancel) -> تعود السيارة إلى "متوفر"
    after_cancel: function(frm) {
        if (frm.doc.car) {
            frappe.db.set_value('Car', frm.doc.car, 'status', 'متوفر')
                .then(() => {
                    frappe.show_alert({
                        message: __('تم إلغاء العقد وإرجاع حالة السيارة {0} إلى [متوفر] بنجاح', [frm.doc.car]),
                        indicator: 'green'
                    });
                });
        }
    }
});

frappe.ui.form.on('Car Booking', {
    validate: function(frm) {
        if (frm.doc.start_date && frm.doc.end_date) {
            let diff_days = frappe.datetime.get_diff(frm.doc.end_date, frm.doc.start_date) + 1;
            
            if (diff_days < 3) {
                // استخدام frappe.throw هو الحل القياسي المضمون لإيقاف الحفظ وعرض الخطأ فوراً
                frappe.throw(__('ممنوع تأجير السيارات لأقل من 3 أيام كحد أدنى.<br>عدد الأيام بالتاريخ الحالي هو: {0} أيام فقط.', [diff_days]));
            }
        }
    },
    setup: function(frm) {
        frm.set_query('car', function() {
            let filters = {
                'status': 'متوفر' // عرض السيارات المتوفرة فقط
            };
            if (frm.doc.category_car) {
                // الفلترة بالاسم البرمجي الصحيح في مستند Car وهو 'categorize'
                filters['categorize'] = frm.doc.category_car;
            }
            return { filters: filters };
        });
    },

    refresh: function(frm) {
        calculate_rental_financials(frm);
    },

    start_date: function(frm) {
        calculate_rental_financials(frm);
    },

    end_date: function(frm) {
        calculate_rental_financials(frm);
    },

    category_car: function(frm) {
        // حساب المالية مجدداً عند تغيير التصنيف
        calculate_rental_financials(frm);

        // مسح اختيار السيارة إذا قام الموظف بتغيير التصنيف لسيارة لا تطابق التصنيف الجديد
        if (frm.doc.car) {
            frappe.db.get_value('Car', frm.doc.car, 'categorize')
                .then(r => {
                    let values = r.message || r;
                    if (values && values.categorize !== frm.doc.category_car) {
                        frm.set_value('car', '');
                        frappe.show_alert({
                            message: __('تم تفريغ حقل السيارة لأنها لا تنتمي للتصنيف المختار الجديد'),
                            indicator: 'orange'
                        });
                    }
                });
        }
    },

    // جلب تصنيف السيارة تلقائياً بمجرد اختيار السيارة
    car: function(frm) {
        if (frm.doc.car) {
            frappe.db.get_value('Car', frm.doc.car, 'categorize')
                .then(r => {
                    let values = r.message || r;
                    if (values && values.categorize) {
                        frm.set_value('category_car', values.categorize);
                    }
                    calculate_rental_financials(frm);
                });
        } else {
            calculate_rental_financials(frm);
        }
    }
});

function calculate_rental_financials(frm) {
    if (!frm.doc.start_date || !frm.doc.end_date || !frm.doc.category_car) {
        frm.set_value('duration_days', 0);
        frm.set_value('rate_per_day', 0);
        if (frm.fields_dict['cost']) {
            frm.set_value('cost', 0);
        }
        return;
    }

    // 1. حساب عدد الأيام الفعلي وتحديثه في الخانة
    let diff_days = frappe.datetime.get_diff(frm.doc.end_date, frm.doc.start_date) + 1;
    if (diff_days < 1) {
        diff_days = 0;
    }
    frm.set_value('duration_days', diff_days);

    if (diff_days <= 0) {
        frm.set_value('rate_per_day', 0);
        frm.set_value('cost', 0);
        return;
    }

    // 2. تحديد الباقة المطلوبة من تصنيف السيارات بناءً على عدد الأيام
    let target_field = 'small_term'; // الباقة الصغرى (3-7 أيام)
    if (diff_days > 7 && diff_days <= 20) {
        target_field = 'med_term';   // الباقة الوسطى (7-20 يوماً)
    } else if (diff_days > 20) {
        target_field = 'long_term';  // الباقة الكبرى (فوق 20 يوماً)
    }

    // 3. جلب الباقة من مستند Car Category المختار
    frappe.db.get_value('Car Category', frm.doc.category_car, target_field)
        .then(r => {
            let res = r.message || r;
            let package_id = res[target_field];

            if (package_id) {
                // قراءة السعر اليومي المباشر المخزن في اسم الباقة (مثال: "50" أو "40" أو "30")
                let daily_rate = flt(package_id) || 0;

                // تقريب السعر اليومي لمنزلتين عشريتين
                daily_rate = parseFloat(daily_rate.toFixed(2));
                frm.set_value('rate_per_day', daily_rate);

                // 4. حساب التكلفة الفعلية الإجمالية مباشرة بالضرب في السعر اليومي للباقة
                let total_cost = diff_days * daily_rate;
                total_cost = Math.round(total_cost); // تقريب لعدد صحيح ليطابق حقل cost (نوعه Int)

                if (frm.fields_dict['cost']) {
                    frm.set_value('cost', total_cost);
                }
            } else {
                frm.set_value('rate_per_day', 0);
                frm.set_value('cost', 0);
            }
        });
}

