frappe.ui.form.on('Car Receipt', {
    refresh: function(frm) {
        calculate_rental_financials(frm);
    },
    // حساب التكلفة فوراً بمجرد قيام الموظف بتعديل تاريخ الاستلام الفعلي
    receiving_date: function(frm) {
        calculate_rental_financials(frm);
    },
    // إعادة الحساب عند تعديل تاريخ التسليم في العقد
    pickup_date: function(frm) {
        calculate_rental_financials(frm);
    },
    // جلب تاريخ البدء برمجياً فور اختيار عقد الحجز المرتبط وإعادة الحساب
    booking: function(frm) {
        if (frm.doc.booking) {
            frappe.db.get_value('Car Booking', frm.doc.booking, 'start_date')
                .then(r => {
                    let values = r.message || r;
                    if (values && values.start_date) {
                        frm.set_value('pickup_date', values.start_date);
                        calculate_rental_financials(frm);
                    }
                });
        } else {
            frm.set_value('pickup_date', '');
            frm.set_value('real_days', 0);
            frm.set_value('mainly_cost', 0);
        }
    },
    // منع الحفظ النهائي للاستلام إذا كانت المدة الفعلية أقل من 3 أيام كحد أدنى
    validate: function(frm) {
        if (frm.doc.pickup_date && frm.doc.receiving_date) {
            let diff_days = frappe.datetime.get_diff(frm.doc.receiving_date, frm.doc.pickup_date);
            
            if (diff_days < 3) {
                frappe.throw(__('ممنوع تأجير السيارات لأقل من 3 أيام كحد أدنى.<br>عدد الأيام بالتاريخ الحالي هو: <b>{0} أيام فقط</b>.', [diff_days]));
            }
        }
    }
});

function calculate_rental_financials(frm) {
    // التحقق من توفر الحقول اللازمة لعملية الحساب لتفادي توقف الكود
    if (!frm.doc.pickup_date || !frm.doc.receiving_date || !frm.doc.booking) {
        frm.set_value('real_days', 0);
        frm.set_value('mainly_cost', 0);
        return;
    }

    // 1. حساب عدد الأيام الفعلي وتحديثه في الخانة
    let diff_days = frappe.datetime.get_diff(frm.doc.receiving_date, frm.doc.pickup_date);
    if (diff_days < 0) {
        diff_days = 0;
    }
    frm.set_value('real_days', diff_days);

    if (diff_days <= 0) {
        frm.set_value('mainly_cost', 0);
        return;
    }

    // 2. جلب تصنيف السيارة (category_car) برمجياً من عقد الحجز المرتبط (Car Booking)
    frappe.db.get_value('Car Booking', frm.doc.booking, 'category_car')
        .then(r => {
            let values = r.message || r;
            let category_name = values ? values.category_car : null;

            if (category_name) {
                // 3. تحديد نوع الباقة المطلوبة بناءً على الأيام الفعلية المحسوبة
                let target_field = 'small_term'; // الباقة الصغرى (3-7 أيام)
                if (diff_days > 7 && diff_days <= 20) {
                    target_field = 'med_term';   // الباقة الوسطى (7-20 يوماً)
                } else if (diff_days > 20) {
                    target_field = 'long_term';  // الباقة الكبرى (فوق 20 يوماً)
                }

                // 4. جلب الباقة السعرية من مستند Car Category المختار
                frappe.db.get_value('Car Category', category_name, target_field)
                    .then(res_cat => {
                        let package_info = res_cat.message || res_cat;
                        let package_id = package_info ? package_info[target_field] : null;

                        if (package_id) {
                            // قراءة السعر اليومي المباشر المخزن في اسم الباقة (مثال: "50" أو "40" أو "30")
                            let daily_rate = flt(package_id) || 0;

                            // 5. حساب الكلفة الأساسية الإجمالية وتقريبها لعدد صحيح ليطابق حقل mainly_cost (نوعه Int)
                            let total_cost = diff_days * daily_rate;
                            total_cost = Math.round(total_cost); 

                            if (frm.fields_dict['mainly_cost']) {
                                frm.set_value('mainly_cost', total_cost);
                            }
                        } else {
                            frm.set_value('mainly_cost', 0);
                        }
                    });
            } else {
                frm.set_value('mainly_cost', 0);
            }
        });
}

