function style_license_card(frm) {
    const group = ["رقم_رخصة_القيادة", "مكان_الإصدار", "تاريخ_الاصدار", "تاريخ_الانتهاء"];
    group.forEach((fn, i) => {
        const f = frm.fields_dict[fn];
        if (!f || !f.$wrapper) return;
        const $w = f.$wrapper;
        $w.css({
            "background": "#cbffce",
            "border-left": "1px solid #a5d6a7",
            "border-right": "1px solid #a5d6a7",
            "padding": "8px 14px",
            "margin": "0"
        });
        if (i === 0) {
            $w.css({
                "border-top": "1px solid #a5d6a7",
                "border-top-left-radius": "12px",
                "border-top-right-radius": "12px",
                "padding-top": "14px",
                "margin-top": "10px"
            });
        }
        if (i === group.length - 1) {
            $w.css({
                "border-bottom": "1px solid #a5d6a7",
                "border-bottom-left-radius": "12px",
                "border-bottom-right-radius": "12px",
                "padding-bottom": "14px",
                "margin-bottom": "12px",
                "box-shadow": "0 2px 6px rgba(0,0,0,0.06)"
            });
        }
    });
}

