function gc_booking_phone(frm) {
    return frm.doc.international_phone || frm.doc["custom_رقم_الهاتف_المحمول"] || frm.doc.phone_fetched || "";
}

function gc_wa_open(phoneStr, message) {
    const p = (phoneStr || "").replace(/[^0-9]/g, "");
    window.open("https://wa.me/" + p + "?text=" + encodeURIComponent(message), "_blank");
}

function gc_send_one(frm, doctype, name, print_format, noun) {
    frappe.call({
        method: "gatecar.api.get_share_url",
        args: { doctype: doctype, name: name, print_format: print_format, no_letterhead: 0 },
        freeze: true,
        freeze_message: __("جارٍ تجهيز الرابط العام..."),
        callback: (r) => {
            if (!r.message) return;
            const cust = frm.doc.customer_name_fetched || "";
            gc_wa_open(gc_booking_phone(frm), `مرحباً ${cust}،\nمرفق رابط ${noun} (${name}):\n${r.message}`);
        },
    });
}

function gc_send_inspection(frm, inspection_type, print_format, noun) {
    frappe.db.get_list("Car Inspection", {
        filters: { booking: frm.docname, inspection_type: inspection_type },
        fields: ["name"], order_by: "creation desc", limit: 1,
    }).then((rows) => {
        if (!rows || !rows.length) { frappe.msgprint(__("لا يوجد {0} مرتبط بهذا العقد", [noun])); return; }
        gc_send_one(frm, "Car Inspection", rows[0].name, print_format, noun);
    });
}

function gc_send_final_invoice(frm) {
    frappe.db.get_list("Car Receipt", {
        filters: { booking: frm.docname },
        fields: ["name"], order_by: "creation desc", limit: 1,
    }).then((rows) => {
        if (!rows || !rows.length) { frappe.msgprint(__("لا توجد فاتورة نهائية مرتبطة بهذا العقد")); return; }
        gc_send_one(frm, "Car Receipt", rows[0].name, "فاتورة استلام سيارة", "الفاتورة النهائية");
    });
}

function gc_send_all_receipts(frm) {
    frappe.db.get_list("Revenue", {
        filters: { booking_reference: frm.docname },
        fields: ["name", "payment_type"], order_by: "creation asc", limit: 100,
    }).then((rows) => {
        if (!rows || !rows.length) { frappe.msgprint(__("لا توجد إيصالات مالية مرتبطة بهذا العقد")); return; }
        frappe.dom.freeze(__("جارٍ تجهيز روابط الإيصالات..."));
        const tasks = rows.map((rv) => {
            const pf = rv.payment_type === "دفع" ? "Payment Receipt" : "Revenue Receipt";
            const kind = rv.payment_type === "دفع" ? "دفع" : "قبض";
            return frappe.xcall("gatecar.api.get_share_url", {
                doctype: "Revenue", name: rv.name, print_format: pf, no_letterhead: 0,
            }).then((url) => `• (${kind}) ${rv.name}: ${url}`);
        });
        Promise.all(tasks).then((lines) => {
            frappe.dom.unfreeze();
            const cust = frm.doc.customer_name_fetched || "";
            gc_wa_open(gc_booking_phone(frm), `مرحباً ${cust}،\nمرفق روابط الإيصالات المالية للحجز ${frm.docname}:\n${lines.join("\n")}`);
        }).catch(() => frappe.dom.unfreeze());
    });
}
